#nullable enable // autogenerated

using MVZ2.UI.Map;
using MVZ2Logic.Maps;
using PVZEngine.Base;
using UnityEngine;

namespace MVZ2.Map
{
    public partial class MapElement : MonoBehaviour, IMapElement
    {
        public void Init(IMapInterface map, MapElementDefinition definition)
        {
            Map = map;
            Definition = definition;
        }
        public void SetActive(bool value)
        {
            gameObject.SetActive(value);
        }

        private void Awake()
        {
            if (button.Exists())
                button.OnClick += OnClickCallback;
        }
        private void OnClickCallback(MapElementButton button)
        {
            Definition.OnClick(this);
        }

        public IMapInterface Map { get; private set; } = null!;
        public MapElementDefinition Definition { get; private set; } = null!;
        [SerializeField]
        private MapElementButton? button;
        public NamespaceIDReference? definitionID;
    }
}
